package interview2026;

public class Split_String_to_EqualLength_Substring {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

String s = "abcdefighijkl";

int size = 3;      // we can find length of string and have an idea in how many parts it will split

for(int i=0;i<s.length();i=i+3)
{
	System.out.println(s.substring(i,i+size));
	
}
		
		
		
		
		
		
		
		
		
		
		
		
		
		
		
		
		
		
		
		
		
	}

}
